  1	import * as React from 'react';
  2	import {
  3	  MultipleFileUpload,
  4	  MultipleFileUploadMain,
  5	  MultipleFileUploadStatus,
  6	  MultipleFileUploadStatusItem,
  7	  HelperText,
  8	  HelperTextItem,
  9	} from '@patternfly/react-core';
 10	
 11	type ReadFile = {
 12	  fileName: string;
 13	  data?: string;
 14	  loadResult?: 'danger' | 'success';
 15	  loadError?: DOMException;
 16	};
 17	
 18	enum Status {
 19	  InProgress = 'inProgress',
 20	  Success = 'success',
 21	  Danger = 'danger',
 22	  Error = 'error',
 23	}
 24	
 25	type UploadFilePickerProps = {
 26	  infoText: string;
 27	  titleText: string;
 28	  acceptedFiles: string;
 29	  uploadLimit?: number;
 30	  onFileUpload: (currentFiles: File[]) => void;
 31	  compatibleFileFilter?: (file: File) => boolean;
 32	  uploadedFiles?: File[];
 33	};
 34	const UploadFilePicker: React.FC<UploadFilePickerProps> = ({
 35	  onFileUpload,
 36	  infoText,
 37	  titleText,
 38	  uploadLimit,
 39	  compatibleFileFilter,
 40	  uploadedFiles = [],
 41	}) => {
 42	  const [currentFiles, setCurrentFiles] = React.useState<File[]>(
 43	    uploadedFiles.filter((file) => file != null)
 44	  );
 45	  const [readFileData, setReadFileData] = React.useState<ReadFile[]>([]);
 46	  const [showStatus, setShowStatus] = React.useState(false);
 47	  const [statusIcon, setStatusIcon] = React.useState(Status.InProgress);
 48	
 49	  if (!showStatus && currentFiles.length > 0) {
 50	    setShowStatus(true);
 51	  }
 52	
 53	  React.useEffect(() => {
 54	    if (readFileData.length < currentFiles.length) {
 55	      setStatusIcon(Status.InProgress);
 56	    } else if (
 57	      readFileData.every((file) => file.loadResult === Status.Success)
 58	    ) {
 59	      setStatusIcon(Status.Success);
 60	    } else {
 61	      setStatusIcon(Status.Danger);
 62	    }
 63	    onFileUpload(currentFiles);
 64	  }, [readFileData, currentFiles, onFileUpload]);
 65	
 66	  const removeFiles = (namesOfFilesToRemove: string[]) => {
 67	    const newCurrentFiles = currentFiles.filter(
 68	      (currentFile) =>
 69	        !namesOfFilesToRemove.some((fileName) => fileName === currentFile.name)
 70	    );
 71	
 72	    setCurrentFiles(newCurrentFiles);
 73	
 74	    const newReadFiles = readFileData.filter(
 75	      (readFile) =>
 76	        !namesOfFilesToRemove.some((fileName) => fileName === readFile.fileName)
 77	    );
 78	
 79	    setReadFileData(newReadFiles);
 80	  };
 81	
 82	  const updateCurrentFiles = (files: File[]) => {
 83	    setCurrentFiles((prevFiles) => [...prevFiles, ...files]);
 84	  };
 85	
 86	  const handleFileDrop = (_event, droppedFiles: File[]) => {
 87	    // identify what, if any, files are re-uploads of already uploaded files
 88	    const currentFileNames = currentFiles.map((file) => file.name);
 89	    const reUploads = droppedFiles.filter((droppedFile) =>
 90	      currentFileNames.includes(droppedFile.name)
 91	    );
 92	
 93	    const compatibleFiles = droppedFiles.filter(compatibleFileFilter);
 94	    Promise.resolve()
 95	      .then(() => removeFiles(reUploads.map((file) => file.name)))
 96	      .then(() => updateCurrentFiles(compatibleFiles));
 97	  };
 98	
 99	  const handleReadSuccess = (data: string, file: File) => {
100	    setReadFileData((prevReadFiles) => [
101	      ...prevReadFiles,
102	      { data, fileName: file.name, loadResult: Status.Success },
103	    ]);
104	  };
105	
106	  const handleReadFail = (error: DOMException, file: File) => {
107	    setReadFileData((prevReadFiles) => [
108	      ...prevReadFiles,
109	      { loadError: error, fileName: file.name, loadResult: Status.Danger },
110	    ]);
111	  };
112	
113	  const createHelperText = (file: File) => {
114	    const fileResult = readFileData.find(
115	      (readFile) => readFile.fileName === file.name
116	    );
117	    if (fileResult?.loadError) {
118	      return (
119	        <HelperText isLiveRegion>
120	          <HelperTextItem variant={Status.Error}>
121	            {fileResult.loadError.toString()}
122	          </HelperTextItem>
123	        </HelperText>
124	      );
125	    }
126	  };
127	
128	  return (
129	    <MultipleFileUpload onFileDrop={handleFileDrop}>
130	      <MultipleFileUploadMain
131	        titleText={titleText}
132	        infoText={infoText}
133	        isUploadButtonHidden={currentFiles.length === uploadLimit}
134	      />
135	      {showStatus && (
136	        <MultipleFileUploadStatus statusToggleIcon={statusIcon}>
137	          {currentFiles.map((file) => (
138	            <MultipleFileUploadStatusItem
139	              file={file}
140	              key={file.name}
141	              onClearClick={() => removeFiles([file.name])}
142	              onReadSuccess={handleReadSuccess}
143	              onReadFail={handleReadFail}
144	              progressHelperText={createHelperText(file)}
145	            />
146	          ))}
147	        </MultipleFileUploadStatus>
148	      )}
149	    </MultipleFileUpload>
150	  );
151	};
152	
153	export default UploadFilePicker;

